## Common patterns

### Loading state

While the Button component doesn't have a built-in `isLoading` prop yet, you can implement a loading state by disabling the button and showing a spinner.

```jsx live-dev
const App = () => {
  const [isLoading, setIsLoading] = useState(false);

  const handleClick = () => {
    setIsLoading(true);
    // Simulate async action
    setTimeout(() => setIsLoading(false), 2000);
  };

  return (
    <Button 
      isDisabled={isLoading} 
      onPress={handleClick}
    >
      {isLoading ? 'Loading...' : 'Save Changes'}
    </Button>
  );
}
```

## Testing your implementation

These examples demonstrate how to test your implementation when using Button in your application. As the component's internal functionality is already tested by Nimbus, these patterns help you verify your integration and application-specific logic.

### Basic Rendering Tests

Verify the Button renders with expected content and attributes

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { Button, NimbusProvider } from "@commercetools/nimbus";

describe("Button - Basic rendering", () => {
  it("renders with correct text", () => {
    render(
      <NimbusProvider>
        <Button>Click me</Button>
      </NimbusProvider>
    );

    expect(
      screen.getByRole("button", { name: /click me/i })
    ).toBeInTheDocument();
  });

  it("renders with custom data attributes", () => {
    render(
      <NimbusProvider>
        <Button data-testid="my-button">Action</Button>
      </NimbusProvider>
    );

    expect(screen.getByTestId("my-button")).toBeInTheDocument();
  });

  it("renders as an anchor element when using the as prop", () => {
    render(
      <NimbusProvider>
        <Button as="a" href="/home" data-testid="link-button">
          Go Home
        </Button>
      </NimbusProvider>
    );

    const element = screen.getByTestId("link-button");
    expect(element.tagName).toBe("A");
    expect(element).toHaveAttribute("href", "/home");
  });
});
```

### Interaction Tests

Test user interactions with the Button

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { Button, NimbusProvider } from "@commercetools/nimbus";

describe("Button - Interactions", () => {
  it("calls onPress when clicked", async () => {
    const user = userEvent.setup();
    const handlePress = vi.fn();

    render(
      <NimbusProvider>
        <Button onPress={handlePress}>Action</Button>
      </NimbusProvider>
    );

    const button = screen.getByRole("button", { name: /action/i });
    await user.click(button);

    expect(handlePress).toHaveBeenCalledTimes(1);
  });

  it("does not call onPress when disabled", async () => {
    const user = userEvent.setup();
    const handlePress = vi.fn();

    render(
      <NimbusProvider>
        <Button isDisabled onPress={handlePress}>
          Action
        </Button>
      </NimbusProvider>
    );

    const button = screen.getByRole("button", { name: /action/i });
    await user.click(button);

    expect(handlePress).not.toHaveBeenCalled();
  });
});
```

### Keyboard Navigation Tests

Test keyboard interactions with the Button

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { Button, NimbusProvider } from "@commercetools/nimbus";

describe("Button - Keyboard navigation", () => {
  it("is focusable with Tab key", async () => {
    const user = userEvent.setup();

    render(
      <NimbusProvider>
        <Button>Focus me</Button>
      </NimbusProvider>
    );

    const button = screen.getByRole("button", { name: /focus me/i });
    await user.tab();

    expect(button).toHaveFocus();
  });

  it("can be activated with Enter key", async () => {
    const user = userEvent.setup();
    const handlePress = vi.fn();

    render(
      <NimbusProvider>
        <Button onPress={handlePress}>Press me</Button>
      </NimbusProvider>
    );

    const button = screen.getByRole("button", { name: /press me/i });
    button.focus();

    await user.keyboard("{Enter}");

    expect(handlePress).toHaveBeenCalledTimes(1);
  });

  it("can be activated with Space key", async () => {
    const user = userEvent.setup();
    const handlePress = vi.fn();

    render(
      <NimbusProvider>
        <Button onPress={handlePress}>Press me</Button>
      </NimbusProvider>
    );

    const button = screen.getByRole("button", { name: /press me/i });
    button.focus();

    await user.keyboard(" ");

    expect(handlePress).toHaveBeenCalledTimes(1);
  });
});
```

### State Tests

Test different states of the Button

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { Button, NimbusProvider } from "@commercetools/nimbus";

describe("Button - States", () => {
  it("applies disabled state on native button", () => {
    render(
      <NimbusProvider>
        <Button isDisabled>Disabled</Button>
      </NimbusProvider>
    );

    const button = screen.getByRole("button", { name: /disabled/i });
    expect(button).toBeDisabled();
  });

  it("is not focusable when disabled", async () => {
    const user = userEvent.setup();

    render(
      <NimbusProvider>
        <Button isDisabled>Cannot focus</Button>
      </NimbusProvider>
    );

    const button = screen.getByRole("button", { name: /cannot focus/i });
    await user.tab();

    expect(button).not.toHaveFocus();
  });
});
```

### Visual Variant Tests

Test rendering with different visual variants and sizes

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { Button, NimbusProvider } from "@commercetools/nimbus";

